INITIAL_DEFECTS = 3

def _relabel(s):
    if s.get("accepted"):
        s["status"] = "accepted"
    elif not s.get("attempted"):
        s["status"] = "idle"
    elif not s.get("verified"):
        s["status"] = "draft"
    elif s.get("passing"):
        s["status"] = "passing"
    else:
        s["status"] = "failing"
    return s

def transition(state, action):
    s = dict(state)
    a = action.get("name")

    if a == "attempt":
        # Produce a fresh candidate (unless the work is already finalized).
        if not s.get("accepted"):
            s["attempted"] = True
            s["verified"] = False
            s["passing"] = False
            s["defects"] = INITIAL_DEFECTS
            s["attempts"] = s.get("attempts", 0) + 1

    elif a == "verify":
        # Check the current candidate; record pass/fail. Does not edit it.
        if s.get("attempted") and not s.get("accepted"):
            s["verified"] = True
            s["passing"] = s.get("defects", 0) == 0
            s["checks"] = s.get("checks", 0) + 1

    elif a == "fix":
        # Repair one detected defect; invalidate the prior verification.
        if (s.get("attempted") and not s.get("accepted")
                and s.get("verified") and s.get("defects", 0) > 0):
            s["defects"] = s.get("defects", 0) - 1
            s["verified"] = False
            s["passing"] = False
            s["fixes"] = s.get("fixes", 0) + 1

    elif a == "accept":
        # Finalize only a verified, defect-free candidate. Terminal.
        if s.get("verified") and s.get("defects", 0) == 0 and not s.get("accepted"):
            s["accepted"] = True

    return _relabel(s)

